public:
    int data;
    Node* next;
    Node(int data) {
        this->data = data;
        this->next = nullptr;
    }
};

void solve(Node* head) {
    // TODO: implement
    while (head != nullptr) {
        cout << head->data << endl;
        head = head->next;
    }
    return;
}

