import sys
it = iter(sys.stdin.read().split())
n = int(next(it))
class Node:
    def __init__(self, data):
        self.data = data
        self.next = None
head = None
prev = None
for _ in range(n):
    data = int(next(it))
    node = Node(data)
    if head is None:
        head = node
    else:
        prev.next = node
    prev = node
while head:
    print(head.data)
    head = head.next

solutions.cpp:
#include <bits/stdc++.h>
using namespace std;
struct Node {
    int data;
    Node* next;
    Node(int data) {
        this->data = data;
        this->next = nullptr;
    }
};
int main() {
    int n;
    cin >> n;
    Node* head = nullptr;
    Node* prev = nullptr;
    for (int i = 0; i < n; i++) {
        int data;
        cin >> data;
        Node* node = new Node(data);
        if (head == nullptr) {
            head = node;
        } else {
            prev->next = node;
        }
        prev = node;
    }
    while (head) {
        cout << head->data << endl;
        head = head->next;
    }
    return 0;
}
